SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- Table structure for config_info
-- ----------------------------
DROP TABLE IF EXISTS `config_info`;
CREATE TABLE `config_info`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `data_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'data_id',
  `group_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '分组ID',
  `content` longtext CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'content',
  `md5` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'md5',
  `gmt_create` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `gmt_modified` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  `src_user` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT 'source user',
  `src_ip` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'source ip',
  `app_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '应用名称',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT '租户字段',
  `c_desc` varchar(256) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '配置描述',
  `c_use` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'use',
  `effect` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'effect',
  `type` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '类型',
  `c_schema` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT 'schema',
  `encrypted_data_key` text CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '秘钥',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_configinfo_datagrouptenant`(`data_id` ASC, `group_id` ASC, `tenant_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 469 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'config_info' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of config_info
-- ----------------------------
INSERT INTO `config_info` VALUES (361, 'cmict-share.yaml', 'DEFAULT_GROUP', 'spring:\n  datasource:\n    dynamic:\n      # 设置默认数据源\n      primary: master\n      # 是否设置严格模式，默认false不启动，启动后在未匹配到指定数据源时候回抛出异常，不启动会使用默认数据源\n      strict: true\n      datasource:\n        master:\n          type: com.zaxxer.hikari.HikariDataSource\n          pool-name: HikariCP\n          driver-class-name: com.p6spy.engine.spy.P6SpyDriver\n          url: jdbc:p6spy:mysql://mysql:3306/frame_admin_demo?serverTimezone=Asia/Shanghai&useUnicode=true&characterEncoding=utf8&autoReconnect=true&useSSL=false\n          username: root\n          password: passw0rd\n        slave:\n          type: com.zaxxer.hikari.HikariDataSource\n          pool-name: HikariCP\n          driver-class-name: com.p6spy.engine.spy.P6SpyDriver\n          url: jdbc:p6spy:mysql://mysql:3306/aict?serverTimezone=Asia/Shanghai&useUnicode=true&characterEncoding=utf8&autoReconnect=true&useSSL=false\n          username: root\n          password: passw0rd\n          # driver-class-name: com.kingbase8.Driver\n          # url: jdbc:kingbase8://kdb.meteion-dev:54321/kingbase/frame_admin_demo\n          # username: aict\n          # password: DmPassword2023\n          \n      # 数据库连接池配置\n      hikari:\n        # 连接池中允许的最小连接数，默认值10，当空闲连接低于该值且总连接数低于最大连接数时，HikariCP会立即添加连接来保证一个高效的性能\n        min-idle: 5\n        # 连接池中允许的最大连接数，默认值10，当连接数达到该值时，新的连接申请会被阻塞直到超时\n        max-pool-size: 20\n        # 自动提交\n        is-auto-commit: true\n        # 空闲连接超时时间（毫秒），超时则被释放，即间隔多久检测一次需要关闭的空闲连接，最小10秒\n        idle-timeout: 6000\n        # 一个连接的生命时长（毫秒），超时而且没被使用则被释放，最小30秒，建议设置比数据库超时时长少30秒\n        max-lifetime: 300000\n        # 等待连接池分配连接的最大时长（毫秒），超过这个时长还没可用的连接则发生SQLException\n        connection-timeout: 30000\n        # 数据库连接测试语句\n        connection-test-query: SELECT 1\n  redis:\n    cluster:\n      nodes: redis-cluster-0.redis-cluster-headless.aict.svc.cluster.local:6379,redis-cluster-1.redis-cluster-headless.aict.svc.cluster.local:6379,redis-cluster-2.redis-cluster-headless.aict.svc.cluster.local:6379,redis-cluster-3.redis-cluster-headless.aict.svc.cluster.local:6379,redis-cluster-4.redis-cluster-headless.aict.svc.cluster.local:6379,redis-cluster-5.redis-cluster-headless.aict.svc.cluster.local:6379\n    database: 0\n    password: Redis@Passw0rd\n    timeout: 30s\n    lettuce:\n      pool:\n        # 连接池最大连接数（使用负值表示没有限制）\n        max-active: 200\n        # 连接池中的最大空闲连接\n        max-idle: 10\n        # 连接池中的最小空闲连接\n        min-idle: 0\n        # 连接池最大阻塞等待时间（使用负值表示没有限制）\n        max-wait: 30s\n\n# swagger配置\nknife4j:\n  enable: false\n  basic:\n    enable: true\n    username: admin\n    password: admin123@AAA\n\n# 是否开启认证拦截器\nauth:\n  filter:\n    enable: false\n  whiteUrl: /**/login,/**/login/**,/cmict/aict-springai-api/voice-recognition,/**/conversationManager/open/stream/v1/chat/completions,/**/sso/om/ticket/verify,/**/sso/om/ticket,/**/oauth/callback,/**/sms-login,/**/submit-tokens,/**/password-change/sms,/**/sms-reset-pwd,/**/user/me,/cmict/aict-springai-api/common/file/download,/cmict/aict-springai-api/appSettings,/**/goods/**,/**/goods-category/list,/**/business-customers-banner/list,/**/goods-file/**,/**/homeCount,/**/robotManagerShare/ollamaForStream/**,/**/robotManagerShare/getShareDetailByCode/**,/**/robotManagerShare/modelChatForDoc,/**/rge/share/url,/**/sso/zhxt/user/process,/**/robotManagerShare/getShareDetailByCode\nmybatis-plus:\n  global-config:\n    db-config:\n      date-format: yyyy-MM-dd HH:mm:ss', '509682074e0d6e8892e64f363cb8e3bd', '2025-04-30 03:22:23', '2026-03-30 09:00:38', 'nacos', '120.211.73.113', '', 'frame', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (362, 'cmict-gateway.yaml', 'DEFAULT_GROUP', 'spring:\n  codec:\n    # 缓冲区大小\n    max-in-memory-size: 1000MB\n  servlet:\n    # 设置文件上传限制\n    multipart:\n      enabled: true\n      maxRequestSize: 1000MB\n      maxFileSize: 100MB\n  cloud:\n    gateway:\n      # 网关超时配置\n      httpclient:\n        connect-timeout: 10000\n        response-timeout: 1200s\n      # 全局跨域配置\n      globalcors:\n        cors-configurations:\n          \'[/**]\':\n            ## 不允许写道凭证\n            allowCredentials: false\n            ## 允许所有域名\n            allowed-origins: \"*\" \n            allowedOriginPatterns: \"*\"\n            ## 允许所有http方法\n            allowedMethods: \"*\"\n            allowedHeaders: \"*\"\n            maxAge: 1800\n        add-to-simple-url-handler-mapping: true\n      # 相同header多个值时的处理方式，三种规则可选（RETAIN_FIRST|RETAIN_UNIQUE|RETAIN_LAST）\n      default-filters:\n        - DedupeResponseHeader=Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_FIRST\n      # 网关路由配置\n      routes:\n        # 认证授权服务\n        - id: auth-service\n          uri: lb://cmict-auth\n          predicates:\n            - Path=/cmict/auth/**\n        # 日志存储服务\n        - id: logstore-service\n          uri: lb://cmict-logstore\n          predicates:\n            - Path=/cmict/logstore/**\n        # 后台管理服务\n        - id: admin-service\n          uri: lb://cmict-admin\n          predicates:\n            - Path=/cmict/admin/**\n        # 文件服务\n        - id: file-service\n          uri: lb://cmict-file\n          predicates:\n            - Path=/cmict/file/**\n        # 定时任务服务\n        - id: job-service\n          uri: lb://cmict-job\n          predicates:\n            - Path=/cmict/job/**\n        # portal服务\n        - id: portal-service\n          uri: lb://cmict-portal\n          predicates:\n            - Path=/cmict/portal/**\n        # 代码生成服务\n        - id: gencode-service\n          uri: lb://cmict-gencode\n          predicates:\n            - Path=/cmict/gencode/**\n        # onemsg服务\n        - id: onemsg-service\n          uri: lb://cmict-onemsg\n          predicates:\n            - Path=/cmict/onemsg/**\n    loadbalancer:\n      # 负载均衡器缓存\n      cache:\n        enabled: true\n        caffeine:\n          spec: initialCapacity=50,maximumSize=1000,expireAfterWrite=5s\ngateway:\n  # 网关认证配置\n  auth:\n    enable: true\n    clientBusiness: TOB\n    endpoint: http://cmict-auth\n    timeout: 5000\n    authPath: /cmict/auth/token/verify\n    whitePath: \n      - Path=/cmict/workflow/**/image\n      - Path=/cmict/auth/need-login\n      - Path=/cmict/auth/sms-login\n      - Path=/cmict/auth/sms-reset-pwd\n      - Path=/cmict/auth/external/om/sso\n      - Path=/cmict/auth/external/portal/sso\n      - Path=/cmict/aict-springai-api/robotManagerShare/getShareDetailByCode\n      - Path=/cmict/aict-springai-api/appSettings\n  # 是否采集日志\n  log:\n    enable: true\n  # 安全模式：0 普通，1 IP验证，2 签名验证，3 签名验证+返回数据加密\n  security:\n    cmict-auth:\n      mode: 0\n    cmict-admin:\n      mode: 0\n    cmict-file:\n      mode: 0\n\n# 关闭knife4j的增强功能\nknife4j:\n  enable: false\n\ncmict:\n  gateway:\n    res:\n      ignoreUri: /cmict/*\n\nurl:\n  admin: http://admin-server.aict-framework:9630', 'a2205bb2106efdec11d2c9710b71c214', '2025-04-30 03:22:23', '2025-08-25 11:37:32', 'nacos', '10.233.102.0', '', 'frame', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (363, 'cmict-gateway-route.yaml', 'DEFAULT_GROUP', 'routes:\n  # 认证授权服务\n  - id: auth-service\n    uri: lb://cmict-auth\n    predicates:\n      - Path=/cmict/auth/**\n  # 日志存储服务\n  - id: logstore-service\n    uri: lb://cmict-logstore\n    predicates:\n      - Path=/cmict/logstore/**\n  # 后台管理服务\n  - id: admin-service\n    uri: lb://cmict-admin\n    predicates:\n      - Path=/cmict/admin/**\n# 业务服务\n  - id: one-berry-business\n    uri: lb://one-berry-business\n    predicates:\n      - Path=/cmict/one-berry-business/** \n# java - 智能体服务\n  - id: springai\n    uri: http://aict-springai-api:8000\n    predicates:\n      - Path=/cmict/aict-springai-api/** \n# java - 智能体服务\n  - id: agent\n    uri: http://aict-springai-api:8000\n    predicates:\n      - Path=/agent/** \n# java - 预览服务\n  - id: aict-kkfileview\n    uri: http://aict-kkfileview:8012\n    predicates:\n      - Path=/cmict/aict-kkfileview/**\n    filters:\n      - StripPrefix=2\n', 'b900ac3d95cab2ce8fc8045b93852c3a', '2025-04-30 03:22:23', '2025-07-23 04:15:24', 'nacos', '10.233.102.0', '', 'frame', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (364, 'cmict-auth.yaml', 'DEFAULT_GROUP', '\n# swagger配置\nknife4j:\n  enable: true\n  basic:\n    enable: true\n    username: admin\n    password: admin123@AAA\n\n# 是否开启认证拦截器\nauth:\n  filter:\n    enable: false\n  login:\n    index: http://framework-aict3-30746.d.onecode.cmict.cloud/login\n    jmpUrl: http://framework-aict3-30746.d.onecode.cmict.cloud/login\n    \nsecurity:\n  kickOut:\n    maxSession: 100000 \n\n# 认证server给client颁发的秘钥等信息\n\nunity-desktop:\n portal-key: 12345678\n client-id: 1820640538838347778\n client-secret: tygzt        \n\n### 我们作为客户端 对接别人的单点\noauth2:\n  client-id: 78a6d9e35ec647c185ea2bcb7a77e8f2\n  client-secret: efdb83bb33cc4ba08dd28f591ffaa476\n  redirect-uri: http://your-app-domain/oauth/callback\n  authorize-url: http://xx.xx.xxx.xxx/idp/oauth2/authorize\n  token-url: http://xx.xx.xxx.xxx/idp/oauth2/getToken\n  user-info-url: http://xx.xx.xxx.xxx/idp/oauth2/getUserInfo\nchat:\n  url: 1\n\nhb-sso:\n  oauth2:\n    client-id: 1927631865645621248\n    client-secret: FFtxRO904P5+ljYy1tmzKQ==\n    authorize-url: https://sso.hebamr.cn\n    appId: 002025052831865008087040\n    redirect-uri: http://188.21.25.171:30080\n    security-key: 80e7221ab4ec83a384742511f1327922\n    privateKey: MIGTAgEAMBMGByqGSM49AgEGCCqBHM9VAYItBHkwdwIBAQQgrYX2e61I9LB+mGvA8IEfEFKG+WqD69gRPs26pQwwjH2gCgYIKoEcz1UBgi2hRANCAAQJnmUhCjv5AwBVZKijwyHeGDxx6DYzuv29tNt/5gCyKAzSiHWmPxLD37NMhBnFEvRYEStX8vvM2QQqBUpoFzHU\n    publicKey: MFkwEwYHKoZIzj0CAQYIKoEcz1UBgi0DQgAECZ5lIQo7+QMAVWSoo8Mh3hg8ceg2M7r9vbTbf+YAsigM0oh1pj8Sw9+zTIQZxRL0WBErV/L7zNkEKgVKaBcx1A==\nom-sso:\n  oauth2:\n    authorize-url: http://gateway-scaffoldsaas-30746.p.onecode.cmict.cloud\n    client-secret: fc54f9655dc04da486663f1055978ba8\n    client-user: 13a38a1bfd214a3abd27d393de2189b5\n    service-url: https://oneberry-h5-dev-30746.p.onecode.cmict.cloud/#/pages/auth/index\n    account: gdfjsk2kxtTodoApp\n    secret:  \"&6pmzp&p$@$j$z\"\n\n# smsCode:\n#   apId: berry\n#   secretKey: