INSERT INTO `config_info` VALUES (365, 'cmict-admin.yaml', 'DEFAULT_GROUP', 'security:\n  kickOut:\n    maxSession: 10\n\n# 统一框架配置\ncmict:\n  # 门户配置\n  portal:\n    # 是否启用门户\n    enable: true\n    # 不启用门户时，自定义门户地址\n    custom:\n      url: \"/front/home\"    \n\n# 是否开启认证拦截器\nauth:\n  filter:\n    enable: false\naict:\n  url: http://gateway-server.aict-framework:9610/cmict/kubegems/v2/tenant\n  resource: http://gateway-server.aict-framework:9610/cmict/pai/v2/regions/\n\nonemsg:\n  username:\n    type: phone\n\nagent: \n  login: \n    url: https://agentengine-test-30746.p.onecode.cmict.cloud/berry-apps/apis/login\n    username: trKVtkCrn6H7P9yRNRpDng==\n    password: 381XDRPnt9lBCvKk8VBoNw==\n  system:\n    url: https://agentengine-test-30746.p.onecode.cmict.cloud/apis/system/\n    userid: 691698e9a14642381c7b6051\n  apps:\n    url: https://agentengine-test-30746.p.onecode.cmict.cloud/apis/engine/v1/apps/berry/apps\n# 智能体平台url\nagentengine:\n  system:\n    url: https://agentengine-test-30746.p.onecode.cmict.cloud\n    fronturl: https://agentengine-test-30746.p.onecode.cmict.cloud\n  sync:\n    enabled: true\naict-springai:\n  url: https://oneberry-dev-30746.p.onecode.cmict.cloud/cmict/aict-springai-api', '7f2225593f9c58df6b89093ba6a1c914', '2025-04-30 03:22:23', '2026-02-26 08:50:21', 'nacos', '10.233.102.0', '', 'frame', '', '', '', 'yaml', '', '');
