INSERT INTO `config_info` VALUES (414, 'one-berry-business.yaml', 'DEFAULT_GROUP', '#应用配置\nspring:\n  datasource:\n    #springboot3.0 默认集成HikariCP数据库连接池，此处使用缺省配置即可\n    driver-class-name: com.p6spy.engine.spy.P6SpyDriver\n    url: jdbc:p6spy:mysql://mysql:3306/aict?serverTimezone=Asia/Shanghai&useUnicode=true&characterEncoding=utf8&autoReconnect=true&useSSL=false\n    username: root\n    password: jGwPiZjGwPiZ\n\n\n#########################公共配置##############################\ncommon:\n  sensitive:\n    enabled: false #日志是否脱敏\n    keyword: userName #脱敏关键字，多个字段用逗号隔开\n  log:\n    request: true #请求日志\n    response: true #响应日志\n    feignRequest: true #feign请求日志\n    feignResponse: true #feign响应日志\nfeign:\n  client:\n    config:\n      default:\n        connectTimeout: 50000\n        readTimeout: 50000\n        loggerLevel: basic\nlogging:\n  level:\n    com.cmict.ms: debug\n    com.baomidou.mybatisplus: info\n    org.apache.kafka: off\n\ndecorator:\n  datasource:\n    p6spy:\n      enable-logging: true #是否开启p6spy日志\n      multiline: true', '502adbd67d057b72c501bbbc28af4daf', '2025-07-22 12:28:24', '2025-08-07 09:06:14', 'nacos', '10.233.102.0', '', 'frame', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` VALUES (454, 'cmict-gateway-route-base', 'DEFAULT_GROUP', 'routes:\n  # 认证授权服务\n  - id: auth-service\n    uri: lb://cmict-auth\n    predicates:\n      - Path=/cmict/auth/**\n  # 日志存储服务\n  - id: logstore-service\n    uri: lb://cmict-logstore\n    predicates:\n      - Path=/cmict/logstore/**\n  # 后台管理服务\n  - id: admin-service\n    uri: lb://cmict-admin\n    predicates:\n      - Path=/cmict/admin/**\n# 业务服务\n  - id: one-berry-business\n    uri: lb://one-berry-business\n    predicates:\n      - Path=/cmict/one-berry-business/** \n# java - 智能体服务\n  - id: springai\n    uri: http://aict-springai-api:8000\n    predicates:\n      - Path=/cmict/aict-springai-api/** \n# java - 智能体服务\n  - id: agent\n    uri: http://aict-springai-api:8000\n    predicates:\n      - Path=/agent/** \n# java - 预览服务\n  - id: aict-kkfileview\n    uri: http://aict-kkfileview:8012\n    predicates:\n      - Path=/cmict/aict-kkfileview/**\n    filters:\n      - StripPrefix=2\n', 'b900ac3d95cab2ce8fc8045b93852c3a', '2025-12-29 14:03:46', '2025-12-29 14:03:46', 'nacos', '127.0.0.1', '', 'frame', NULL, NULL, NULL, 'text', NULL, '');

