INSERT INTO `his_config_info` VALUES (365, 465, 'cmict-admin.yaml', 'DEFAULT_GROUP', '', 'security:\n  kickOut:\n    maxSession: 10\n\n# 统一框架配置\ncmict:\n  # 门户配置\n  portal:\n    # 是否启用门户\n    enable: true\n    # 不启用门户时，自定义门户地址\n    custom:\n      url: \"/front/home\"    \n\n# 是否开启认证拦截器\nauth:\n  filter:\n    enable: false\naict:\n  url: http://gateway-server.aict-framework:9610/cmict/kubegems/v2/tenant\n  resource: http://gateway-server.aict-framework:9610/cmict/pai/v2/regions/\n\nonemsg:\n  username:\n    type: phone\n\nagent: \n  login: \n    url: https://agentengine-dev-30746.p.onecode.cmict.cloud/apis/login \n    username: V6c80QxeaXUFgnrbFtH/KQ== \n    password: aXS1yOBD9a1gP+2srhPEgQ==\n  system:\n    url: https://agentengine-dev-30746.p.onecode.cmict.cloud/apis/system/\n    userid: 691698e9a14642381c7b6051\n  apps:\n    url: https://agentengine-dev-30746.p.onecode.cmict.cloud/apis/engine/v1/apps/berry/apps\n# 智能体平台url\nagentengine:\n  system:\n    url: https://agentengine-dev-30746.p.onecode.cmict.cloud\n  sync:\n    enabled: true\naict-springai:\n  url: https://oneberry-test-30746.p.onecode.cmict.cloud/cmict/aict-springai-api', 'd4446a479b16dbd861fe0ba7f505ccc4', '2026-02-06 17:17:20', '2026-02-06 09:17:20', 'nacos', '10.233.102.0', 'U', 'frame', '');
