INSERT INTO `his_config_info` VALUES (365, 467, 'cmict-admin.yaml', 'DEFAULT_GROUP', '', 'security:\n  kickOut:\n    maxSession: 10\n\n# 统一框架配置\ncmict:\n  # 门户配置\n  portal:\n    # 是否启用门户\n    enable: true\n    # 不启用门户时，自定义门户地址\n    custom:\n      url: \"/front/home\"    \n\n# 是否开启认证拦截器\nauth:\n  filter:\n    enable: false\naict:\n  url: http://gateway-server.aict-framework:9610/cmict/kubegems/v2/tenant\n  resource: http://gateway-server.aict-framework:9610/cmict/pai/v2/regions/\n\nonemsg:\n  username:\n    type: phone\n\nagent: \n  login: \n    url: https://agentengine-test-30746.p.onecode.cmict.cloud/apis/login \n    username: trKVtkCrn6H7P9yRNRpDng==\n    password: 381XDRPnt9lBCvKk8VBoNw==\n  system:\n    url: https://agentengine-test-30746.p.onecode.cmict.cloud/apis/system/\n    userid: 691698e9a14642381c7b6051\n  apps:\n    url: https://agentengine-test-30746.p.onecode.cmict.cloud/apis/engine/v1/apps/berry/apps\n# 智能体平台url\nagentengine:\n  system:\n    url: https://agentengine-test-30746.p.onecode.cmict.cloud\n    fronturl: https://agentengine-test-30746.p.onecode.cmict.cloud\n  sync:\n    enabled: true\naict-springai:\n  url: https://oneberry-dev-30746.p.onecode.cmict.cloud/cmict/aict-springai-api', 'bc035304dfc80c6f0a590326f97bee16', '2026-02-26 16:50:20', '2026-02-26 08:50:21', 'nacos', '10.233.102.0', 'U', 'frame', '');
INSERT INTO `his_config_info` VALUES (361, 468, 'cmict-share.yaml', 'DEFAULT_GROUP', '', 'spring:\n  datasource:\n    dynamic:\n      # 设置默认数据源\n      primary: master\n      # 是否设置严格模式，默认false不启动，启动后在未匹配到指定数据源时候回抛出异常，不启动会使用默认数据源\n      strict: true\n      datasource:\n        master:\n          type: com.zaxxer.hikari.HikariDataSource\n          pool-name: HikariCP\n          driver-class-name: com.p6spy.engine.spy.P6SpyDriver\n          url: jdbc:p6spy:mysql://mysql:3306/frame_admin_demo?serverTimezone=Asia/Shanghai&useUnicode=true&characterEncoding=utf8&autoReconnect=true&useSSL=false\n          username: root\n          password: jGwPiZjGwPiZ\n        slave:\n          type: com.zaxxer.hikari.HikariDataSource\n          pool-name: HikariCP\n          driver-class-name: com.p6spy.engine.spy.P6SpyDriver\n          url: jdbc:p6spy:mysql://mysql:3306/aict?serverTimezone=Asia/Shanghai&useUnicode=true&characterEncoding=utf8&autoReconnect=true&useSSL=false\n          username: root\n          password: jGwPiZjGwPiZ\n          # driver-class-name: com.kingbase8.Driver\n          # url: jdbc:kingbase8://kdb.meteion-dev:54321/kingbase/frame_admin_demo\n          # username: aict\n          # password: DmPassword2023\n          \n      # 数据库连接池配置\n      hikari:\n        # 连接池中允许的最小连接数，默认值10，当空闲连接低于该值且总连接数低于最大连接数时，HikariCP会立即添加连接来保证一个高效的性能\n        min-idle: 5\n        # 连接池中允许的最大连接数，默认值10，当连接数达到该值时，新的连接申请会被阻塞直到超时\n        max-pool-size: 20\n        # 自动提交\n        is-auto-commit: true\n        # 空闲连接超时时间（毫秒），超时则被释放，即间隔多久检测一次需要关闭的空闲连接，最小10秒\n        idle-timeout: 6000\n        # 一个连接的生命时长（毫秒），超时而且没被使用则被释放，最小30秒，建议设置比数据库超时时长少30秒\n        max-lifetime: 300000\n        # 等待连接池分配连接的最大时长（毫秒），超过这个时长还没可用的连接则发生SQLException\n        connection-timeout: 30000\n        # 数据库连接测试语句\n        connection-test-query: SELECT 1\n  redis:\n    host: redis\n    port: 6379\n    database: 2\n    username: default\n    password: \n    timeout: 30s\n    lettuce:\n      pool:\n        # 连接池最大连接数（使用负值表示没有限制）\n        max-active: 200\n        # 连接池中的最大空闲连接\n        max-idle: 10\n        # 连接池中的最小空闲连接\n        min-idle: 0\n        # 连接池最大阻塞等待时间（使用负值表示没有限制）\n        max-wait: 30s\n\n# swagger配置\nknife4j:\n  enable: false\n  basic:\n    enable: true\n    username: admin\n    password: admin123@AAA\n\n# 是否开启认证拦截器\nauth:\n  filter:\n    enable: false\n  whiteUrl: /**/login,/**/login/**,/cmict/aict-springai-api/voice-recognition,/**/conversationManager/open/stream/v1/chat/completions,/**/sso/om/ticket/verify,/**/sso/om/ticket,/**/oauth/callback,/**/sms-login,/**/submit-tokens,/**/password-change/sms,/**/sms-reset-pwd,/**/user/me,/cmict/aict-springai-api/appSettings,/**/goods/**,/**/goods-category/list,/**/business-customers-banner/list,/**/goods-file/**,/**/homeCount,/**/robotManagerShare/ollamaForStream/**,/**/robotManagerShare/getShareDetailByCode/**,/**/robotManagerShare/modelChatForDoc,/**/rge/share/url,/**/sso/zhxt/user/process,/**/robotManagerShare/getShareDetailByCode\nmybatis-plus:\n  global-config:\n    db-config:\n      date-format: yyyy-MM-dd HH:mm:ss', 'f2baf12631863d1f18c6dbf4d8060bda', '2026-03-19 02:53:55', '2026-03-19 02:53:56', 'nacos', '120.211.73.77', 'U', 'frame', '');
INSERT INTO `his_config_info` VALUES (361, 469, 'cmict-share.yaml', 'DEFAULT_GROUP', '', 'spring:\n  datasource:\n    dynamic:\n      # 设置默认数据源\n      primary: master\n      # 是否设置严格模式，默认false不启动，启动后在未匹配到指定数据源时候回抛出异常，不启动会使用默认数据源\n      strict: true\n      datasource:\n        master:\n          type: com.zaxxer.hikari.HikariDataSource\n          pool-name: HikariCP\n          driver-class-name: com.p6spy.engine.spy.P6SpyDriver\n          url: jdbc:p6spy:mysql://mysql:3306/frame_admin_demo?serverTimezone=Asia/Shanghai&useUnicode=true&characterEncoding=utf8&autoReconnect=true&useSSL=false\n          username: root\n          password: passw0rd\n        slave:\n          type: com.zaxxer.hikari.HikariDataSource\n          pool-name: HikariCP\n          driver-class-name: com.p6spy.engine.spy.P6SpyDriver\n          url: jdbc:p6spy:mysql://mysql:3306/aict?serverTimezone=Asia/Shanghai&useUnicode=true&characterEncoding=utf8&autoReconnect=true&useSSL=false\n          username: root\n          password: passw0rd\n          # driver-class-name: com.kingbase8.Driver\n          # url: jdbc:kingbase8://kdb.meteion-dev:54321/kingbase/frame_admin_demo\n          # username: aict\n          # password: DmPassword2023\n          \n      # 数据库连接池配置\n      hikari:\n        # 连接池中允许的最小连接数，默认值10，当空闲连接低于该值且总连接数低于最大连接数时，HikariCP会立即添加连接来保证一个高效的性能\n        min-idle: 5\n        # 连接池中允许的最大连接数，默认值10，当连接数达到该值时，新的连接申请会被阻塞直到超时\n        max-pool-size: 20\n        # 自动提交\n        is-auto-commit: true\n        # 空闲连接超时时间（毫秒），超时则被释放，即间隔多久检测一次需要关闭的空闲连接，最小10秒\n        idle-timeout: 6000\n        # 一个连接的生命时长（毫秒），超时而且没被使用则被释放，最小30秒，建议设置比数据库超时时长少30秒\n        max-lifetime: 300000\n        # 等待连接池分配连接的最大时长（毫秒），超过这个时长还没可用的连接则发生SQLException\n        connection-timeout: 30000\n        # 数据库连接测试语句\n        connection-test-query: SELECT 1\n  redis:\n    cluster:\n      nodes: redis-cluster-0.redis-cluster-headless.aict.svc.cluster.local:6379,redis-cluster-1.redis-cluster-headless.aict.svc.cluster.local:6379,red